class Solution(object):
    def centeredSubarrays(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            total = 0
            elements = set()
            for j in range(i, n):
                total += nums[j]
                elements.add(nums[j])
                if total in elements:
                    count += 1
        return count
